--Rezolva?i urmatoarele cerinte folosind clauza WHERE. --X1. Toate comenzile din martie 2012 (doua modalita?i).SELECT *FROM Sales.SalesOrderHeaderWHERE YEAR(OrderDate) = 2012 AND MONTH(OrderDate) = 3SELECT *FROM Sales.SalesOrderHeaderWHERE OrderDate >= '20120301' AND OrderDate < '20120401'--X2. Toate produsele care nu con?in cifre în nume, sunt negre ?i pot avea marimile L ?i XL (doua modalita?i).SELECT *FROM Production.ProductWHERE Name NOT LIKE '%[0-9]%' AND Color = 'Black'AND Size IN ('L', 'XL')SELECT *FROM Production.ProductWHERE CHARINDEX('0', Name) = 0 AND CHARINDEX('1', Name) = 0 AND CHARINDEX('2', Name) = 0 AND CHARINDEX('3', Name) = 0 AND CHARINDEX('4', Name) = 0 AND CHARINDEX('5', Name) = 0AND CHARINDEX('6', Name) = 0 AND CHARINDEX('7', Name) = 0 AND CHARINDEX('8', Name) = 0 AND CHARINDEX('9', Name) = 0AND Color = 'Black'AND Size IN ('L','XL')--X3. Crea?i un query care sa returneze toate persoanele care con?in apostrof în LastName.SELECT *FROM Person.PersonWHERE LastName LIKE '%''%'--X4. Toate ID-urile pare de produse.SELECT *FROM Production.ProductWHERE ProductID%2 = 0 --X5. Toate comenzile pentru care a trecut mai mult de 7 zile pâna la livrare.SELECT *FROM Sales.SalesOrderHeaderWHERE DATEDIFF(DAY, OrderDate, ShipDate) > 7--X6. Toate comenzile care au fost date intr-o zi impara din luna.SELECT *FROM Sales.SalesOrderHeaderWHERE DAY(OrderDate)%2 = 1--X7. Toate produsele pentru care timpul de fabricare depasteste 2 zile si costa mai putin de 200 sau timpul de fabricare e maxim o zi si costa peste 1000. SELECT *FROM Production.ProductWHERE (DaysToManufacture > 2 AND StandardCost < 200) OR (DaysToManufacture <= 1 AND StandardCost > 1000) --X8. Toate persoanele care si-au modificat datele in ultimele 6 luni calendaristice ale unui an bisect.SELECT *FROM Person.PersonWHERE MONTH(ModifiedDate) BETWEEN 7 AND 12AND ((YEAR(ModifiedDate) % 400 = 0)             OR (YEAR(ModifiedDate) % 4 = 0             AND YEAR(ModifiedDate) % 100 != 0))  --X9. Câ?i JobCandidates au în CV cuvântul 'manager'.SELECT COUNT(*)FROM HumanResources.JobCandidateWHERE LOWER(CAST(Resume AS NVARCHAR(MAX))) LIKE '%manager%'--X10. Un singur câmp cu numele complet al persoanelor (din tabelul Person.Person) pentru care AdditionalContactInfo con?ine stringul 'weekend access'.SELECT CONCAT(FirstName, ' ', MiddleName + ' ', LastName)FROM Person.PersonWHERE CAST(AdditionalContactInfo AS VARCHAR(MAX)) LIKE '%weekend access%'